from collections import Counter
import filtrage

def distance_trigrammes(texte, nb=3, seuil=13, trigramme = ""):
    # Nettoyage simple et découpage en mots
    texte = filtrage.filtrer_uniquement_lettres(texte)
    textetab = [k for k in texte.lower()]
    #print(f"textetab : {textetab}")

    # Création des trigrammes   #trigrammes = ["".join(textetab[i:i+3]) for i in range(len(textetab)-3)]
    trigrammes = ["".join(textetab[i:i+nb]) for i in range(len(textetab)-nb)]
    #print(f"trigrammes : {trigrammes}")

    # Comptage
    occurrences = Counter(trigrammes)
    #print(f"occurrences : {occurrences}")
    resultats_tries = occurrences.items()
    #print(f"resultats_tries : {resultats_tries}")

    # si besoin de remettre dans l'ordre avec sorted
    # resultats_tries = sorted(occurrences.items())
    # print(f"resultats_tries : {resultats_tries}")

    # Affichage des trigrammes fréquents
    print("\n" * 2)
    for tri, count in resultats_tries:
        if count > (seuil*0.8):
            print()
            print(f"'{tri}' apparaît {count} fois")
            if count > seuil:
                find_pos_tri(texte, tri)
    return 0


def find_pos_tri(texte, trigramme_recherche):
    # 1. Nettoyage et mise en minuscule
    textetab = [k.lower() for k in texte if k.isalpha()] # On ne garde que les lettres
    
    # 2. Création de la liste des trigrammes avec leurs positions
    # On crée une liste de tuples : [('the', 0), ('hex', 1), ('exd', 2)...]
    trigrammes_avec_pos = [("".join(textetab[i:i+3]), i) for i in range(len(textetab)-3)]
    
    # 3. Comptage global pour savoir si c'est un trigramme fréquent
    uniquement_les_tris = [t[0] for t in trigrammes_avec_pos]
    occurrences = Counter(uniquement_les_tris)
    
    # 4. Affichage des positions si le trigramme apparaît assez souvent
    if occurrences[trigramme_recherche] > 1:
        print()
        dist = 0
        x=0
        y=0
        print(f"Positions pour le trigramme '{trigramme_recherche}':")
        for tri, pos in trigrammes_avec_pos:
            if tri == trigramme_recherche:
                x = y
                y = pos
                if x>0 : 
                    dist = y-x                
                print(f" -> Trouvé en position : {pos:<8} | distance : {dist} ")
    else:
        print(f"Le trigramme '{trigramme_recherche}' n'est pas assez fréquent.")

    return occurrences[trigramme_recherche]


